

// import http module
const http = require('http');

// get sys info from osdata
const { getSystemInfo } = require('./osdata.js');


// create server
const server = http.createServer((req, res) => {
    
    // get sys info
    const sysInfo = getSystemInfo();

    res.writeHead(200, { 'Content-Type': 'text/html' });

    // generate html content using osdata
    const htmlResponse = `
        <!DOCTYPE html>
        <html>
        <head>
            <title>System Information</title>
            <meta http-equiv="refresh" content="3">
            <style>
                body { 
                    font-family: monospace; 
                    padding: 5px; 
                    background-color: black; /* Sets the background to black */
                    color: white; /* Sets the text to white */
                }
                .info-item { 
                    margin-bottom: 25px; 
                }
            </style>
        </head>
        <body>
            <h1>System Information</h1>
            <div id="timer">Refreshing in <span id="count">3</span>s...</div>
            <div class="info-item"><strong>OS Type:</strong> ${sysInfo.osType}</div>
            <div class="info-item"><strong>Architecture:</strong> ${sysInfo.osArch}</div>
            <div class="info-item"><strong>Username:</strong> ${sysInfo.username}</div>
            <div class="info-item"><strong>Uptime:</strong> ${sysInfo.uptimeHours} hours</div>
            <div class="info-item"><strong>Memory:</strong> ${sysInfo.freeMemGB}GB free of ${sysInfo.totalMemGB}GB total</div>
            <div class="info-item"><strong>CPU Cores:</strong> ${sysInfo.cpuCoreCount}</div>
            <div class="info-item"><strong>CPU Model:</strong> ${sysInfo.cpuModel}</div>
            <div class="info-item"><strong>CPU Speed:</strong> ${sysInfo.cpuSpeed} MHz</div>
            <script>
            // Simple countdown timer
            let count = 3;
            const counterElement = document.getElementById('count');
            setInterval(() => {
                count--;
                if (count >= 0) {
                    counterElement.innerText = count;
                }
            }, 1000);
            </script>
        </body>
        </html>
    `;

    
    res.end(htmlResponse);
});

// start server
server.listen(8080, () => {
    console.log(`Server running at http://localhost:8080/`);
});
